mapper.select:
# 尽量避免使用*
select asset_id,name,request_host,risk_level,status from asset

    # 租户隔离由mabatis拦截器实现
    deleted = 0,
    and name like concat('%',#{name},'%')
    and request_host like concat('%',#{requestHost},'%')
    and risk_level = #{riskLevel}
    and status = #{status}
    and category_id = #{categoryId}

order by name desc
